import{_ as i}from"./chunks/Rosenstiel HTML Map May 6.PDJzeEmd.js";import{_ as o,H as s,f as r,i as a,b as n}from"./chunks/framework.D4aZISZY.js";const t="/SeaScan/assets/rectified_timelapse_small.BXMc-VOC.mp4",l="/SeaScan/assets/stitch_1.DbEh4dhc.tif",d="/SeaScan/assets/stitch_2.CBSPrhB4.tif",c="/SeaScan/assets/boats_timelapse.CATc1tr8.mp4",h="/SeaScan/assets/may_6_features.Bmu-M6or.jpg",m="/SeaScan/assets/demo_manual.BLm3eALG.png",y=JSON.parse('{"title":"SeaScan","description":"","frontmatter":{},"headers":[],"relativePath":"overview.md","filePath":"overview.md"}'),u={name:"overview.md"};function p(f,e,g,_,b,w){return s(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="seascan" tabindex="-1">SeaScan <a class="header-anchor" href="#seascan" aria-label="Permalink to &quot;SeaScan&quot;">​</a></h1><p>Constructing maps of flat regions should be a relatively simple task, but conventional approaches require complicated structure-from-motion pipelines intended for full 3D reconstruction. These methods often fail on scenes without dinstiguishable details, such as the ocean. We overcome this limitation through the use of target(s) and GPS data to stitch maps that are focused at a singular depth.</p><h3 id="map-of-waters-near-the-rosenstiel-school-using-the-mavic-3e" tabindex="-1">Map of Waters Near the Rosenstiel School using the MAVIC 3E <a class="header-anchor" href="#map-of-waters-near-the-rosenstiel-school-using-the-mavic-3e" aria-label="Permalink to &quot;Map of Waters Near the Rosenstiel School using the MAVIC 3E&quot;">​</a></h3><div style="display:flex;justify-content:space-around;"><img src="'+i+'" alt="drawing" width="300"><video controls src="'+t+'" width="300"></video></div><h2 id="products" tabindex="-1">Products <a class="header-anchor" href="#products" aria-label="Permalink to &quot;Products&quot;">​</a></h2><p>We present to methods of map generation depending on the amount of how much processing should be done during or before viewing.</p><h3 id="folium-map" tabindex="-1">Folium Map <a class="header-anchor" href="#folium-map" aria-label="Permalink to &quot;Folium Map&quot;">​</a></h3><p>The simplest and quickest result is a map made with folium. It populates a map with a subset of downsampled images stacked on top of each other. While this is quick to generate, the tiles overlap and your browser may switch between these tiles.</p>',8),n("iframe",{src:"https://npikielny.github.io/SeaScan/figures/march_20_folium.html",frameborder:"0",width:"100%",height:"500px",allowfullscreen:""},null,-1),a('<h3 id="stitched-image" tabindex="-1">Stitched Image <a class="header-anchor" href="#stitched-image" aria-label="Permalink to &quot;Stitched Image&quot;">​</a></h3><p>Using our derived GPS transformation we can stitch together high-quality images with limited noise from glint and parallax. This work is ongoing and the transforms of the corresponding geotiffs need correction.</p><div style="display:flex;justify-content:space-around;"><img src="'+l+'" alt="drawing" width="300"><img src="'+d+'" alt="drawing" width="300"></div><h3 id="timelapse-videos" tabindex="-1">Timelapse Videos <a class="header-anchor" href="#timelapse-videos" aria-label="Permalink to &quot;Timelapse Videos&quot;">​</a></h3><p>Lastly, we can collate data around a particular region to get an idea of 3D shape, as well as, an idea of the accuracy of our GPS to image mapping. Notice in May 1, the image transform is slightly off, so objects on the sea surface appear to move.</p><div style="display:flex;justify-content:space-around;"><video controls src="'+t+'" width="300"></video><video controls src="'+c+'" width="300"></video></div><h3 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h3><ol><li>Sea Surface Target</li></ol><p>Our method was designed to automatically detect mooring buoys for boats; however, manually isolating a target in just a few images yields similar results. Thus, our method can be used on any type of target with minimal effort.</p><ol start="2"><li>GPS Data</li></ol><p>Our method uses GPS data, as well as gimbal heading data to align images. We designed with the Mavic 3E in mind, so the meta data should be found at <code>GimbalYawDegree</code> and <code>GimbalPitchDegree</code>. However, if these do no suit your data, you can edit the <code>gps.py</code> file.</p><ol start="3"><li>Camera Calibration (optional)</li></ol><p>In designing for the Mavic 3E, we also included parameters for its image undistortion. We included a notebook that leverage&#39;s <a href="https://docs.opencv.org/3.4/dc/dbb/tutorial_py_calibration.html" target="_blank" rel="noreferrer">OpenCV checkerboard camera calibration</a>. This can be found in <code>Calibration.ipynb</code>.</p><div style="display:flex;justify-content:space-around;"><img src="'+h+'" alt="drawing" width="300"><img src="'+m+'" alt="drawing" width="300"></div>',14)])])}const q=o(u,[["render",p]]);export{y as __pageData,q as default};
